# Invoke-TestResultsAggregator.ps1
#
# Test results aggregator: parses JUnit XML and JSON test result files,
# aggregates totals across a matrix build, identifies flaky tests, and
# generates a GitHub Actions markdown job summary.
#
# TDD build-up (see Invoke-TestResultsAggregator.Tests.ps1):
#   Cycle 1 RED/GREEN  — Parse-JUnitXml
#   Cycle 2 RED/GREEN  — Parse-JsonResults
#   Cycle 3 RED/GREEN  — Aggregate-TestResults
#   Cycle 4 RED/GREEN  — Find-FlakyTests
#   Cycle 5 RED/GREEN  — New-MarkdownSummary
#   REFACTOR           — helpers extracted, error handling unified
#
# Usage (direct):
#   ./Invoke-TestResultsAggregator.ps1 -InputPaths ./fixtures/junit-results-1.xml, ./fixtures/json-results-1.json
#
# Usage (dot-sourced from tests):
#   . ./Invoke-TestResultsAggregator.ps1   # imports functions without running main body
[CmdletBinding()]
param(
    [string[]]$InputPaths
)

# ──────────────────────────────────────────────────────────────────────────────
# Internal helpers
# ──────────────────────────────────────────────────────────────────────────────

function script:ConvertTo-BaseFileName {
    param([string]$Path)
    return [System.IO.Path]::GetFileName($Path)
}

# ──────────────────────────────────────────────────────────────────────────────
# Cycle 1: Parse-JUnitXml
# Returns a flat array of test-case objects:
#   { Name, Status, Message, File, Duration }
# ──────────────────────────────────────────────────────────────────────────────
function Parse-JUnitXml {
    [CmdletBinding()]
    param(
        [Parameter(Mandatory)]
        [string]$Path
    )

    if (-not (Test-Path $Path)) {
        throw "File not found: '$Path'"
    }

    $raw = Get-Content -Path $Path -Raw -ErrorAction Stop
    try {
        [xml]$xml = $raw
    } catch {
        throw "Invalid XML in file '$Path': $($_.Exception.Message)"
    }

    $baseName = script:ConvertTo-BaseFileName $Path
    $results  = [System.Collections.Generic.List[PSCustomObject]]::new()

    # Support both <testsuites><testsuite> and bare <testsuite>
    $suites = @()
    if ($xml.testsuites -and $xml.testsuites.testsuite) {
        $suites += @($xml.testsuites.testsuite)
    } elseif ($xml.testsuite) {
        $suites += @($xml.testsuite)
    }

    foreach ($suite in $suites) {
        if (-not $suite.testcase) { continue }
        foreach ($tc in @($suite.testcase)) {
            $status  = "passed"
            $message = $null

            if ($tc.failure) {
                $status  = "failed"
                $message = if ($tc.failure.message) { $tc.failure.message } else { $tc.failure.'#text' }
            } elseif ($tc.error) {
                $status  = "failed"
                $message = if ($tc.error.message) { $tc.error.message } else { $tc.error.'#text' }
            } elseif ($null -ne $tc.skipped) {
                $status = "skipped"
            }

            $dur = 0.0
            if ($tc.time) { [double]::TryParse($tc.time,
                [System.Globalization.NumberStyles]::Float,
                [System.Globalization.CultureInfo]::InvariantCulture,
                [ref]$dur) | Out-Null }

            $results.Add([PSCustomObject]@{
                Name     = $tc.name
                Status   = $status
                Message  = $message
                File     = $baseName
                Duration = $dur
            })
        }
    }

    return $results.ToArray()
}

# ──────────────────────────────────────────────────────────────────────────────
# Cycle 2: Parse-JsonResults
# JSON format: { "suite", "duration", "tests": [ { "name", "status", "duration" } ] }
# Returns flat array: { Name, Status, File, Duration }
# ──────────────────────────────────────────────────────────────────────────────
function Parse-JsonResults {
    [CmdletBinding()]
    param(
        [Parameter(Mandatory)]
        [string]$Path
    )

    if (-not (Test-Path $Path)) {
        throw "File not found: '$Path'"
    }

    $raw = Get-Content -Path $Path -Raw -ErrorAction Stop
    try {
        $data = $raw | ConvertFrom-Json -ErrorAction Stop
    } catch {
        throw "Invalid JSON in file '$Path': $($_.Exception.Message)"
    }

    $testsArray = if ($data.tests) { $data.tests } elseif ($data.testcases) { $data.testcases } else { $null }
    if ($null -eq $testsArray) {
        throw "Invalid JSON: no 'tests' or 'testcases' array found in '$Path'"
    }

    $baseName = script:ConvertTo-BaseFileName $Path
    $results  = [System.Collections.Generic.List[PSCustomObject]]::new()

    foreach ($tc in $testsArray) {
        $status = if ($tc.status) { $tc.status.ToLower() } else { "passed" }
        $dur    = 0.0
        if ($null -ne $tc.duration) { $dur = [double]$tc.duration }

        $results.Add([PSCustomObject]@{
            Name     = $tc.name
            Status   = $status
            Message  = $tc.message
            File     = $baseName
            Duration = $dur
        })
    }

    return $results.ToArray()
}

# ──────────────────────────────────────────────────────────────────────────────
# Cycle 3: Aggregate-TestResults
# Accepts the flat concatenated array from all files.
# Returns: { Total, Passed, Failed, Skipped, Duration, FailedTests }
# ──────────────────────────────────────────────────────────────────────────────
function Aggregate-TestResults {
    [CmdletBinding()]
    param(
        [Parameter(Mandatory)]
        [object[]]$AllResults
    )

    $passed      = @($AllResults | Where-Object { $_.Status -eq "passed"  })
    $failed      = @($AllResults | Where-Object { $_.Status -eq "failed"  })
    $skipped     = @($AllResults | Where-Object { $_.Status -eq "skipped" })
    $totalDur    = ($AllResults | Measure-Object -Property Duration -Sum).Sum
    # Round to avoid floating-point accumulation drift
    $totalDur    = [math]::Round($totalDur, 2)

    return [PSCustomObject]@{
        Total       = $AllResults.Count
        Passed      = $passed.Count
        Failed      = $failed.Count
        Skipped     = $skipped.Count
        Duration    = $totalDur
        FailedTests = $failed
    }
}

# ──────────────────────────────────────────────────────────────────────────────
# Cycle 4: Find-FlakyTests
# A test is flaky if it appears in the flat results with BOTH "passed" and
# "failed" statuses (i.e. it passed in some matrix runs and failed in others).
# Returns array of: { Name, Passed, Failed }
# ──────────────────────────────────────────────────────────────────────────────
function Find-FlakyTests {
    [CmdletBinding()]
    param(
        [Parameter(Mandatory)]
        [object[]]$AllResults
    )

    # Group by test name across all files
    $byName = $AllResults | Group-Object -Property Name
    $flaky  = [System.Collections.Generic.List[PSCustomObject]]::new()

    foreach ($group in $byName) {
        $runs    = $group.Group
        $nPass   = @($runs | Where-Object { $_.Status -eq "passed" }).Count
        $nFail   = @($runs | Where-Object { $_.Status -eq "failed" }).Count
        # Flaky: appears more than once AND has at least one pass and one fail
        if ($runs.Count -gt 1 -and $nPass -ge 1 -and $nFail -ge 1) {
            $flaky.Add([PSCustomObject]@{
                Name   = $group.Name
                Passed = $nPass
                Failed = $nFail
            })
        }
    }

    return $flaky.ToArray()
}

# ──────────────────────────────────────────────────────────────────────────────
# Cycle 5: New-MarkdownSummary
# Generates a GitHub Actions job summary in Markdown.
# ──────────────────────────────────────────────────────────────────────────────
function New-MarkdownSummary {
    [CmdletBinding()]
    param(
        [Parameter(Mandatory)]
        [PSCustomObject]$Aggregated,

        [Parameter(Mandatory)]
        [object[]]$FlakyTests
    )

    $agg  = $Aggregated
    $rate = if ($agg.Total -gt 0) { [math]::Round($agg.Passed / $agg.Total * 100, 1) } else { 0 }
    $icon = if ($agg.Failed -eq 0) { "PASS" } else { "FAIL" }

    $sb = [System.Text.StringBuilder]::new()

    $null = $sb.AppendLine("# Test Results Summary [$icon]")
    $null = $sb.AppendLine("")
    $null = $sb.AppendLine("## Totals")
    $null = $sb.AppendLine("")
    $null = $sb.AppendLine("| Metric | Value |")
    $null = $sb.AppendLine("|--------|-------|")
    $null = $sb.AppendLine("| Total Tests | $($agg.Total) |")
    $null = $sb.AppendLine("| Passed | $($agg.Passed) |")
    $null = $sb.AppendLine("| Failed | $($agg.Failed) |")
    $null = $sb.AppendLine("| Skipped | $($agg.Skipped) |")
    $null = $sb.AppendLine("| Duration (s) | $($agg.Duration) |")
    $null = $sb.AppendLine("| Pass Rate | ${rate}% |")
    $null = $sb.AppendLine("")

    # Failed tests detail
    if ($agg.FailedTests -and $agg.FailedTests.Count -gt 0) {
        $null = $sb.AppendLine("## Failed Tests")
        $null = $sb.AppendLine("")
        $null = $sb.AppendLine("| Test | File | Message |")
        $null = $sb.AppendLine("|------|------|---------|")
        foreach ($ft in $agg.FailedTests) {
            $msg = if ($ft.Message) { $ft.Message -replace '\r?\n.*', '' } else { "-" }
            $null = $sb.AppendLine("| $($ft.Name) | $($ft.File) | $msg |")
        }
        $null = $sb.AppendLine("")
    } else {
        $null = $sb.AppendLine("> All tests passed - no failures.")
        $null = $sb.AppendLine("")
    }

    # Flaky tests section
    if ($FlakyTests -and $FlakyTests.Count -gt 0) {
        $null = $sb.AppendLine("## Flaky Tests")
        $null = $sb.AppendLine("")
        $null = $sb.AppendLine("> These tests had inconsistent results across matrix runs.")
        $null = $sb.AppendLine("")
        $null = $sb.AppendLine("| Test | Pass Runs | Fail Runs |")
        $null = $sb.AppendLine("|------|-----------|-----------|")
        foreach ($ft in $FlakyTests) {
            $null = $sb.AppendLine("| $($ft.Name) | $($ft.Passed) | $($ft.Failed) |")
        }
        $null = $sb.AppendLine("")
    }

    return $sb.ToString()
}

# ──────────────────────────────────────────────────────────────────────────────
# Main execution body — only runs when $InputPaths is provided.
# When dot-sourced for testing, this block is skipped.
# ──────────────────────────────────────────────────────────────────────────────
if ($InputPaths) {
    $allResults = [System.Collections.Generic.List[object]]::new()

    foreach ($path in $InputPaths) {
        $ext = [System.IO.Path]::GetExtension($path).ToLower()
        switch ($ext) {
            ".xml"  {
                Write-Host "Parsing JUnit XML: $path"
                $allResults.AddRange(@(Parse-JUnitXml -Path $path))
            }
            ".json" {
                Write-Host "Parsing JSON: $path"
                $allResults.AddRange(@(Parse-JsonResults -Path $path))
            }
            default {
                Write-Warning "Unsupported file type '$ext' for '$path'. Skipping."
            }
        }
    }

    $agg   = Aggregate-TestResults -AllResults $allResults.ToArray()
    $flaky = Find-FlakyTests       -AllResults $allResults.ToArray()
    $md    = New-MarkdownSummary   -Aggregated $agg -FlakyTests $flaky

    # Output markdown to stdout (and to GITHUB_STEP_SUMMARY if available)
    Write-Host $md
    if ($env:GITHUB_STEP_SUMMARY) {
        $md | Out-File -FilePath $env:GITHUB_STEP_SUMMARY -Encoding utf8 -Append
    }

    # Emit machine-readable METRIC lines for test harness assertions
    Write-Host "METRIC:Total=$($agg.Total)"
    Write-Host "METRIC:Passed=$($agg.Passed)"
    Write-Host "METRIC:Failed=$($agg.Failed)"
    Write-Host "METRIC:Skipped=$($agg.Skipped)"
    Write-Host "METRIC:Duration=$($agg.Duration)"
    Write-Host "METRIC:FlakyCount=$($flaky.Count)"
    foreach ($ft in $flaky) {
        Write-Host "METRIC:FlakyTest=$($ft.Name)"
    }
}

